import{_ as r,o as e,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-01.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-01.md"}'),o={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-01.md"};function l(n,t,s,d,h,p){return e(),a("div",null,[...t[0]||(t[0]=[i('<p>💡 光通訊追蹤日報 — 2026年6月1日（週一）</p><blockquote><p><strong>查詢時間</strong>：TST 06:02 (2026-06-01 06:02 = 2026-05-31 22:02 UTC) <strong>昨日敘事延續</strong>：NVIDIA $40 億光子投資 + COMPUTEX 倒數 + 黃仁勳今日 GTC Taipei 演講 + 光通訊4檔漲停 + 大摩點名9檔</p></blockquote><hr><h2 id="🔴-即時指標-每日掃描" tabindex="-1">🔴 即時指標（每日掃描） <a class="header-anchor" href="#🔴-即時指標-每日掃描" aria-label="Permalink to &quot;🔴 即時指標（每日掃描）&quot;">​</a></h2><h3 id="指標1️⃣-輝達-nvidia-—-🔴-今日-gtc-taipei-演講-vera-rubin-架構" tabindex="-1">指標1️⃣ 輝達 NVIDIA — 🔴 今日 GTC Taipei 演講 + Vera Rubin 架構 <a class="header-anchor" href="#指標1️⃣-輝達-nvidia-—-🔴-今日-gtc-taipei-演講-vera-rubin-架構" aria-label="Permalink to &quot;指標1️⃣ 輝達 NVIDIA — 🔴 今日 GTC Taipei 演講 + Vera Rubin 架構&quot;">​</a></h3><p><strong>最新動態（6/1）</strong>：</p><ul><li><strong>黃仁勳 GTC Taipei 演講</strong>：<strong>6/1（今日）</strong> 台北流行音樂中心</li><li><strong>Vera Rubin 架構</strong>：Vera CPU + Rubin GPU，機櫃級超級電腦，宣稱 10 年 4,000 萬倍算力提升</li><li><strong>NVIDIA 光子投資 $40 億</strong>：向 Coherent 和 Lumentum 各投資 $20 億，取得雷射元件優先使用權</li><li><strong>Spectrum-X Ethernet Photonics</strong>：409.6 Tb/s，<strong>2026 下半年上市</strong></li><li><strong>「A new era of PC」神秘貼文</strong>：5/29 在 X 發布，微軟+Arm 同步轉發，暗示 PC 新時代</li><li><strong>DGX Spark</strong>：搭載 GB10 Grace Blackwell 超級晶片，與聯發科合作</li><li><strong>技術路線圖</strong>： <ul><li>2026：CPO 交換器小規模試產（Scale-out），機櫃內部仍以銅纜為主（Scale-up）</li><li>2027+：CPO 真正爆發</li><li>Feynman 架構：矽光子整合至晶片內部</li></ul></li><li><strong>合作夥伴</strong>：Coherent、Lumentum、Corning、Ayar Labs、Marvell、TSMC</li></ul><p><strong>評估</strong>：今日 GTC Taipei 演講是本週最重要催化劑。Vera Rubin 架構 + 光子投資 $40 億 + Spectrum-X 將決定光通訊族群短期走勢。</p><p>📎 來源：<a href="https://www.nvidia.com/en-tw/gtc/taipei/computex/" target="_blank" rel="noreferrer">NVIDIA</a> · <a href="https://baxtel.com/events/nvidia-gtc-taipei-2026" target="_blank" rel="noreferrer">Baxtel</a> · <a href="https://www.singtaousa.com/2026/05/29/news/usa/nvidia-invests-6-5-billion-yuan-in-photonic-technology-to-target-energy-bottlenecks-in-ai-data-centers/" target="_blank" rel="noreferrer">Singtao USA</a> （T: 06:02 TST）</p><hr><h3 id="指標2️⃣-博通-broadcom-—-🟡-cpo-路線圖持續-無新披露" tabindex="-1">指標2️⃣ 博通 Broadcom — 🟡 CPO 路線圖持續（無新披露） <a class="header-anchor" href="#指標2️⃣-博通-broadcom-—-🟡-cpo-路線圖持續-無新披露" aria-label="Permalink to &quot;指標2️⃣ 博通 Broadcom — 🟡 CPO 路線圖持續（無新披露）&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li>博通在交換器 ASIC 路線圖中明確列出 CPO 版本</li><li>與 NVIDIA 在 CPO 標準上既有競爭也有合作</li><li>2026 年被視為 CPO「商轉元年」，博通是關鍵玩家之一</li><li><strong>但</strong>：具體客戶採用進度未有新披露</li></ul><p><strong>評估</strong>：博通 CPO 策略持續推進，等待 COMPUTEX 進一步消息。</p><p>📎 來源：<a href="https://www.digitimes.com/news/a20260527PD211/ezconn-cpo-siph-2026.html" target="_blank" rel="noreferrer">DigiTimes</a> （T: 06:02 TST）</p><hr><h3 id="指標3️⃣-台積電-tsmc-—-🟢-coupe-進展穩定-盤後鉅額交易新高" tabindex="-1">指標3️⃣ 台積電 TSMC — 🟢 COUPE 進展穩定 + 盤後鉅額交易新高 <a class="header-anchor" href="#指標3️⃣-台積電-tsmc-—-🟢-coupe-進展穩定-盤後鉅額交易新高" aria-label="Permalink to &quot;指標3️⃣ 台積電 TSMC — 🟢 COUPE 進展穩定 + 盤後鉅額交易新高&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li>台積電 COUPE 技術已進入小批量產階段</li><li>與 NVIDIA 合作：將光子技術整合至 GPU 互連系統</li><li>CoWoS 產能持續擴張以滿足 AI 晶片需求</li><li>台積電（2330）5/29 盤中最高 2,360 元新天價，盤後鉅額交易出現 2,442 元新高價</li><li><strong>魏哲家</strong>：員工分紅增幅至少不低於去年（30%），鼓勵員工買進台積電股票</li><li><strong>大摩 COMPUTEX 報告</strong>：台積電為核心供應鏈，目標價維持</li></ul><p><strong>評估</strong>：台積電先進封裝技術是 CPO 量產的關鍵基礎設施，COUPE 進展穩定。</p><p>📎 來源：<a href="https://news.cnyes.com/news/id/6471653" target="_blank" rel="noreferrer">鉅亨網</a> · <a href="https://www.cna.com.tw/news/afe/202605280356.aspx" target="_blank" rel="noreferrer">CNA</a> · <a href="https://www.nvidia.com/en-tw/gtc/taipei/computex/" target="_blank" rel="noreferrer">NVIDIA</a> （T: 06:02 TST）</p><hr><h3 id="指標4️⃣-csp-資本支出-—-🟢-維持高位-nvidia-光子投資間接驗證" tabindex="-1">指標4️⃣ CSP 資本支出 — 🟢 維持高位（NVIDIA 光子投資間接驗證） <a class="header-anchor" href="#指標4️⃣-csp-資本支出-—-🟢-維持高位-nvidia-光子投資間接驗證" aria-label="Permalink to &quot;指標4️⃣ CSP 資本支出 — 🟢 維持高位（NVIDIA 光子投資間接驗證）&quot;">​</a></h3><p>本日無 Microsoft/Google/Amazon/Meta 新的資本支出公告。市場持續關注 AI 基礎設施投資強度。NVIDIA 向光子公司投資 $40 億 → 間接反映 CSP 對光通訊需求的長期看好。</p><p><strong>評估</strong>：CSP 資本支出維持高位，光通訊需求基本面不變。</p><p>📎 來源：無新公告（T: 06:02 TST）</p><hr><h2 id="🟡-台灣供應鏈個股動態" tabindex="-1">🟡 台灣供應鏈個股動態 <a class="header-anchor" href="#🟡-台灣供應鏈個股動態" aria-label="Permalink to &quot;🟡 台灣供應鏈個股動態&quot;">​</a></h2><h3 id="光聖-6442-—-🔴-重大-股東會報喜-泰國標案-computex-催動" tabindex="-1">光聖 (6442) — 🔴 重大：股東會報喜 + 泰國標案 + COMPUTEX 催動 <a class="header-anchor" href="#光聖-6442-—-🔴-重大-股東會報喜-泰國標案-computex-催動" aria-label="Permalink to &quot;光聖 (6442) — 🔴 重大：股東會報喜 + 泰國標案 + COMPUTEX 催動&quot;">​</a></h3><p><strong>5/26 股東會重點</strong>：</p><ul><li><strong>2025 年營運創新高</strong>：合併營收 105.27 億元（+64%），毛利率 57.74%，EPS 23.46 元</li><li><strong>配息</strong>：現金股利 11.8 元（配發率 ~50%），上市以來新高</li><li><strong>2026 展望</strong>：總經理張英華表示，今年銷售、毛利率提升有望超過去（2025）年，全年營收有信心優於去年、維持雙位數成長</li><li><strong>AI 資料中心</strong>：帶動光纖通訊需求倍增，光聖持續布局矽光子（CPO）相關領域</li><li><strong>泰國資料中心標案</strong>：拚年底開花，高芯數產品下半年貢獻營收</li><li><strong>異業結盟</strong>：與英特磊（4971）攜手，延伸至 III-V 族化合物半導體磊晶片（InP）</li><li><strong>子公司合聖</strong>：FAU 產品已送樣美系大廠認證，預計 H2 2026 小量試產</li></ul><p>📎 來源：<a href="https://tw.stock.yahoo.com/news/%E5%85%89%E8%81%96%E8%82%A1%E6%9D%B1%E6%9C%83-ai%E8%B3%87%E6%96%99%E4%B8%AD%E5%BF%83%E5%BB%BA%E7%BD%AE%E5%B8%B6%E5%8B%95%E5%85%89%E7%BA%96%E9%80%9A%E8%A8%8A%E9%9C%80%E6%B1%82%E5%80%8D%E5%A2%9E-%E4%BB%8A%E5%B9%B4%E7%87%9F%E6%94%B6%E6%9C%89%E6%9C%9B%E9%9B%99%E4%BD%8D%E6%95%B8%E6%88%90%E9%95%B7-053518268.html" target="_blank" rel="noreferrer">Yahoo Stock</a> · <a href="https://www.investor.com.tw/MobileHttps/Content.asp?articleNo=14202605260088" target="_blank" rel="noreferrer">Investor.com</a> （T: 06:02 TST）</p><h3 id="光通訊族群-—-🔴-5-25-四檔漲停-波若威、光聖、聯亞、前鼎" tabindex="-1">光通訊族群 — 🔴 5/25 四檔漲停（波若威、光聖、聯亞、前鼎） <a class="header-anchor" href="#光通訊族群-—-🔴-5-25-四檔漲停-波若威、光聖、聯亞、前鼎" aria-label="Permalink to &quot;光通訊族群 — 🔴 5/25 四檔漲停（波若威、光聖、聯亞、前鼎）&quot;">​</a></h3><p><strong>5/25 盤面</strong>：</p><ul><li>波若威（3163）漲停：輝達「背板」名單</li><li>光聖（6442）漲停：股東會前行情</li><li>聯亞（3081）漲停：矽光龍頭</li><li>前鼎（4908）漲停：前4月營收雙位數年增</li><li>聯鈞（3450）+9%、眾達-KY（4977）、光環（3234）、統新（6426）跟漲</li></ul><p><strong>驅動</strong>：黃仁勳來台 + COMPUTEX 展前暖身 + AI 伺服器需求 + 矽光子技術加速</p><p>📎 來源：<a href="https://news.cnyes.com/news/id/6469850" target="_blank" rel="noreferrer">鉅亨網</a> （T: 06:02 TST）</p><h3 id="大摩-computex-報告-—-🔴-點名9檔供應鏈" tabindex="-1">大摩 COMPUTEX 報告 — 🔴 點名9檔供應鏈 <a class="header-anchor" href="#大摩-computex-報告-—-🔴-點名9檔供應鏈" aria-label="Permalink to &quot;大摩 COMPUTEX 報告 — 🔴 點名9檔供應鏈&quot;">​</a></h3><p><strong>大摩預覽報告</strong>（5/29）：</p><ul><li>聚焦重點：輝達 Vera CPU + Rubin GPU、台積電先進封裝、AI 伺服器、CoWoS、CPO</li><li>點名看好：台積電(2330)、聯電(2303)、京元電、日月光、鴻海(2317) 等 9 檔</li><li><strong>但</strong>：專家警告下周可能是短線高點，不宜盲目追高「高位階」、「眾所皆知的背板股」、「走勢轉弱的矽光子與光通訊」</li></ul><p>📎 來源：<a href="https://news.cnyes.com/news/id/6469850" target="_blank" rel="noreferrer">鉅亨網</a> （T: 06:02 TST）</p><h3 id="聯亞-3081" tabindex="-1">聯亞 (3081) <a class="header-anchor" href="#聯亞-3081" aria-label="Permalink to &quot;聯亞 (3081)&quot;">​</a></h3><ul><li>5/25 漲停（矽光龍頭題材）</li><li>MOCVD 機台擴產計畫延續前次</li><li><strong>評估</strong>：本日無法說會或重大公告，延續前次</li></ul><h3 id="上詮-3363" tabindex="-1">上詮 (3363) <a class="header-anchor" href="#上詮-3363" aria-label="Permalink to &quot;上詮 (3363)&quot;">​</a></h3><ul><li>COMPUTEX 展出合作夥伴（Wiwynn CPO 生態系）</li><li><strong>評估</strong>：本日無個股更新，等待 COMPUTEX 展出</li></ul><h3 id="智邦-2345" tabindex="-1">智邦 (2345) <a class="header-anchor" href="#智邦-2345" aria-label="Permalink to &quot;智邦 (2345)&quot;">​</a></h3><ul><li>本日無法說會或重大公告</li><li><strong>評估</strong>：延續前次</li></ul><h3 id="頎邦科技-chipbond" tabindex="-1">頎邦科技 (Chipbond) <a class="header-anchor" href="#頎邦科技-chipbond" aria-label="Permalink to &quot;頎邦科技 (Chipbond)&quot;">​</a></h3><ul><li>光通訊專案訂單能見度已達 <strong>2028 年</strong></li><li>10 個相關專案進行中</li></ul><p>📎 來源：<a href="https://money.udn.com/money/story/5612/9517639" target="_blank" rel="noreferrer">Money UDN</a> （T: 06:02 TST）</p><hr><h2 id="📊-產業趨勢摘要" tabindex="-1">📊 產業趨勢摘要 <a class="header-anchor" href="#📊-產業趨勢摘要" aria-label="Permalink to &quot;📊 產業趨勢摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>趨勢</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>銅退光進</td><td>🟢 持續</td><td>800G/1.6T 光收發需求強勁</td></tr><tr><td>2026 商轉元年</td><td>🟡 關鍵時刻</td><td>Bernstein 報告提醒 CPO 僅小批量出貨</td></tr><tr><td>CPO 量產時程</td><td>🟡 延後風險</td><td>2026 小批量 → 2027 真正爆發</td></tr><tr><td>NVIDIA 光子投資</td><td>🔴 加碼 $40 億</td><td>Coherent + Lumentum 各 $20 億</td></tr><tr><td>台灣供應鏈擴產</td><td>🟢 穩步推進</td><td>光聖股東會報喜、泰國標案、COMPUTEX 催動</td></tr><tr><td>Wiwynn CPO 生態系</td><td>🔴 重大</td><td>全棧展示，合作夥伴含 Ayar Labs/GUC/Corning</td></tr><tr><td>聯發科 CPO</td><td>🔴 重大</td><td>400Gbps CPO + MicroLED，降 50% 功耗</td></tr><tr><td>大摩 COMPUTEX</td><td>🔴 點名9檔</td><td>台積電/聯電/京元電/日月光/鴻海</td></tr><tr><td>光通訊族群漲停</td><td>🔴 5/25 四檔漲停</td><td>波若威/光聖/聯亞/前鼎</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>NVIDIA (2026): GTC Taipei 6/1 演講，Vera Rubin 架構，$40B photonics investment</li><li>Baxtel (2026): GTC Taipei 6/1-4 日程</li><li>Singtao USA (2026-05-29): NVIDIA Coherent/Lumentum $20B each</li><li>鉅亨網 (2026-05-25): 光通訊4檔漲停</li><li>鉅亨網 (2026-05-28): 台積電盤後鉅額交易 $2,442</li><li>CNA (2026-05-28): 台積電 COUPE 進展</li><li>Yahoo Stock (2026-05-26): 光聖股東會，2025營收105億，2026展望樂觀</li><li>Investor.com (2026-05-26): 光聖泰國標案拚年底開花</li><li>鉅亨網 (2026): 大摩 COMPUTEX 報告點名9檔</li><li>Money UDN (2026-05-27): 頎邦訂單能見度至 2028</li><li>DigiTimes (2026-05-27): 博通 CPO 路線圖</li><li>BlockTempo (2026): COMPUTEX 2026 展會概覽</li></ol>',56)])])}const u=r(o,[["render",l]]);export{g as __pageData,u as default};
